customCss:
.single-summary-card-container {
            font-family: 'Noto Sans KR', sans-serif;
            display: flex;
            justify-content: center;
            align-items: center;
            padding: 20px 10px;
            background-color: #f4f6f7;
            margin: 20px 0;
            border-radius: 8px;
        }
        .single-summary-card {
            width: 100%;
            max-width: 700px;
            background-color: #ffffff;
            border-radius: 12px;
            box-shadow: 0 6px 18px rgba(0,0,0,0.12);
            padding: 25px;
            display: flex;
            flex-direction: column;
            overflow: hidden;
            border: 1px solid #ced4da;
            box-sizing: border-box;
        }
        .single-summary-card .card-header {
            display: flex;
            align-items: center;
            border-bottom: 2px solid #2c3e50;
            padding-bottom: 12px;
            margin-bottom: 12px;
        }
        .single-summary-card .card-header-icon {
            font-size: 34px;
            color: #2c3e50;
            margin-right: 14px;
        }
        .single-summary-card .card-header h3 {
            font-size: 24px;
            color: #2c3e50;
            margin: 0;
            line-height: 1.3;
            font-weight: 700;
        }
        .single-summary-card .card-content {
            font-size: 16px;
            line-height: 1.65;
            color: #333;
        }
        .single-summary-card .card-content .section {
            margin-bottom: 12px;
        }
        .single-summary-card .card-content strong {
            color: #2c3e50;
            font-weight: 600;
        }
        .single-summary-card .card-content .highlight {
            background-color: #e8f4fd;
            padding: 2px 6px;
            border-radius: 3px;
            font-weight: bold;
            color: #2c3e50;
        }
        .single-summary-card .card-footer {
            font-size: 14px;
            color: #777;
            text-align: center;
            padding-top: 12px;
            border-top: 1px dashed #ced4da;
            margin-top: auto;
        }
        @media (max-width: 768px) {
            .single-summary-card { padding: 18px; }
            .single-summary-card .card-header-icon { font-size: 28px; }
            .single-summary-card .card-header h3 { font-size: 20px; }
            .single-summary-card .card-content { font-size: 15px; }
        }
